select 
from jst_mall_exchange_order e
left join jst_mall_goods g on g.goods_id = e.goods_id and g.del_flag = '0'
left join jst_user u on u.user_id = e.user_id and u.del_flag = '0'
where e.del_flag = '0'

    and e.exchange_no = #{exchangeNo}


    and e.user_id = #{userId}


    and e.goods_id = #{goodsId}


    and e.status = #{status}

order by e.create_time desc, e.exchange_id desc

select from jst_mall_exchange_order e left join jst_mall_goods g on g.goods_id = e.goods_id and g.del_flag = '0' left join jst_user u on u.user_id = e.user_id and u.del_flag = '0' where e.del_flag = '0' and e.user_id = #{userId}
and e.status = #{status}
order by e.create_time desc, e.exchange_id desc

